use base64::{engine::general_purpose::STANDARD, Engine as _};
use std::{fs, path::Path};

const ICON_PNG_BASE64: &str = "";

fn main() {
    let icon_dir = Path::new("icons");
    let icon_path = icon_dir.join("icon.png");
    if !icon_path.exists() {
        fs::create_dir_all(icon_dir).expect("create Tauri icon directory");
        let bytes = STANDARD.decode(ICON_PNG_BASE64).expect("decode embedded icon");
        fs::write(icon_path, bytes).expect("write embedded icon");
    }
    tauri_build::build()
}
